import type { CashVoucherShellProfile } from '../features/kt/cash-voucher/shared/config/cashVoucherShellProfiles';
import type { PostingReasonInitItem } from '../services/voucherInit/endpoint';
import type { PostingReasonRuleDto } from '../services/kt/models';

/** Map shell → `VoucherRegistry.VoucherTypeCode` cho filter định khoản (parity BE `ResolvePostingReasonVoucherTypeCode`). */
export function resolvePostingReasonVoucherTypeCode(shell: Pick<CashVoucherShellProfile, 'voucherRegistryCode'>): string {
  switch (shell.voucherRegistryCode) {
    case 'giay-bao-co':
      return 'phieu-thu';
    case 'giay-bao-no':
    case 'uy-nhiem-chi':
      return 'phieu-chi';
    default:
      return shell.voucherRegistryCode;
  }
}

export function mapPostingReasonRuleToInitItem(rule: PostingReasonRuleDto): PostingReasonInitItem {
  return {
    code: rule.code,
    name: rule.name,
    debitAccountCode: rule.debitAccountCode,
    creditAccountCode: rule.creditAccountCode,
    erpDebitAccountCode: rule.erpDebitAccountCode,
    erpCreditAccountCode: rule.erpCreditAccountCode,
    allowEditPostingAccounts: rule.allowEditPostingAccounts ?? false,
    suggestOnly: rule.suggestOnly ?? false,
  };
}
